```class Solution {
public:
    int binaryGap(int n) {
        int count = 0;
        int gap = 0;
        while (n != 0) {
            if (n & 1) {
                gap++;
            }
            n >>= 1;
            count++;
        }
        return max(count - gap, 0);
    }
};
```

